import lxml.etree as et
from lxml import objectify
from soappy import WSDLParser, SOAPMessage, SOAPFault

def process_soap_request(xml_data):
    try:
        doc = et.fromstring(xml_data)
        envelope = objectify.ElementTree(doc).getroot()
        if envelope.tag != '{http://schemas.xmlsoap.org/soap/envelope/}Envelope':
            raise Exception("Invalid SOAP Envelope")

        header = envelope.find('.//{http://schemas.xmlsoap.org/soap/header/}Header', namespace_prefixes={'s': 'http://schemas.xmlsoap.org/soap/envelope/'})
        body = envelope.find('.//s:Body', namespace_prefixes={'s': 'http://schemas.xmlsoap.org/soap/envelope/'})

        return {'header': et.tostring(header, encoding='utf-8', method='html'), 'body': et.tostring(body, encoding='utf-8', method='html')}
    except Exception as e:
        raise SOAPFault(f"{e}")